const fs = require('fs');
const path = require('path');
const { Client } = require('pg');

const mapId = 'f6fba025-2917-49da-b252-0caffe2db0d8';
const documentId = '9d09fa89-3a46-465e-a98b-837287c9e22a';
const outPath = path.resolve('C:/repos/oracle/scratchpad-coverage-elements.json');

function norm(s) {
  return String(s ?? '').replace(/\s+/g, ' ').trim();
}

(async () => {
  const client = new Client({ connectionString: process.env.DIRECT_URL, statement_timeout: 30000 });
  await client.connect();

  const confirm = await client.query(`
    select current_database() as db,
           current_user as db_user,
           $1::text as expected_project_ref,
           position($1 in $2) > 0 as url_contains_project_ref
  `, ['eqccjfbyrywsqkxxpjvg', process.env.DIRECT_URL]);

  if (!confirm.rows[0].url_contains_project_ref) {
    throw new Error('Connection URL did not contain expected Supabase project ref');
  }

  const mapResult = await client.query(`
    select id, document_id, status, superseded_by_map_id, nodes_json, edges_json
    from source_workflow_maps
    where id = $1::uuid
  `, [mapId]);
  if (mapResult.rowCount !== 1) throw new Error(`Expected one map row for ${mapId}, got ${mapResult.rowCount}`);
  const map = mapResult.rows[0];
  if (map.document_id !== documentId) throw new Error(`Map document mismatch: ${map.document_id}`);
  if (map.superseded_by_map_id) throw new Error(`Map is superseded by ${map.superseded_by_map_id}`);

  const claimResult = await client.query(`
    select c.id as claim_id,
           c.status,
           c.map_element_ref,
           ce.exact_quote,
           ce.source_document_chunk_id as chunk_id
    from claims c
    join claim_evidence ce on ce.claim_id = c.id
    join document_chunks dc on dc.id = ce.source_document_chunk_id
    where dc.document_id = $1::uuid
      and c.map_element_ref like $2
    order by c.created_at, c.id, ce.id
  `, [documentId, `${mapId}:%`]);

  const nodeById = new Map(map.nodes_json.map((n) => [n.nodeId, n]));
  const claimsByRef = new Map();
  for (const claim of claimResult.rows) {
    if (!claimsByRef.has(claim.map_element_ref)) claimsByRef.set(claim.map_element_ref, []);
    claimsByRef.get(claim.map_element_ref).push(claim);
  }

  const elements = [];
  for (const node of map.nodes_json) {
    const ref = `${mapId}:node:${node.nodeId}`;
    elements.push({
      ref,
      kind: 'node',
      type: node.nodeType ?? null,
      label: node.label ?? node.nodeId,
      lane: node.lane ?? null,
      owner: node.ownerName ?? null,
      evidenceQuote: node.evidenceQuote ?? null,
      chunkId: node.chunkId ?? null,
    });
  }
  for (const edge of map.edges_json) {
    const from = nodeById.get(edge.fromNodeId);
    const to = nodeById.get(edge.toNodeId);
    const baseLabel = `${from?.label ?? edge.fromNodeId} -> ${to?.label ?? edge.toNodeId}`;
    const ref = `${mapId}:edge:${edge.edgeId}`;
    elements.push({
      ref,
      kind: 'edge',
      type: edge.edgeType ?? null,
      label: edge.condition ? `${baseLabel} [condition: ${edge.condition}]` : baseLabel,
      lane: null,
      owner: null,
      evidenceQuote: edge.evidenceQuote ?? null,
      chunkId: edge.chunkId ?? null,
    });
  }

  const quoteCounts = new Map();
  for (const el of elements) {
    const q = norm(el.evidenceQuote);
    if (!q) continue;
    quoteCounts.set(q, (quoteCounts.get(q) ?? 0) + 1);
  }

  const claimsForDifferentRefs = claimResult.rows.filter((c) => c.map_element_ref);
  const rows = elements.map((el) => {
    const q = norm(el.evidenceQuote);
    const covered = (claimsByRef.get(el.ref)?.length ?? 0) > 0;
    const sharedEvidence = Boolean(q) && claimsForDifferentRefs.some((claim) => {
      if (claim.map_element_ref === el.ref) return false;
      const cq = norm(claim.exact_quote);
      return Boolean(cq) && cq.includes(q);
    });
    return {
      ref: el.ref,
      kind: el.kind,
      type: el.type,
      label: el.label,
      lane: el.lane,
      owner: el.owner,
      evidenceQuote: el.evidenceQuote,
      chunkId: el.chunkId,
      covered,
      sharedEvidence,
      quoteAlsoOnOtherElements: Math.max(0, (quoteCounts.get(q) ?? 0) - 1),
    };
  });

  fs.writeFileSync(outPath, JSON.stringify(rows, null, 2) + '\n');

  const uncovered = rows.filter((r) => !r.covered);
  const quoteFanouts = [...quoteCounts.values()].filter((count) => count >= 2);
  const fanoutDistribution = new Map();
  for (const count of quoteFanouts) fanoutDistribution.set(count, (fanoutDistribution.get(count) ?? 0) + 1);

  const summary = {
    dbConfirm: confirm.rows[0],
    map: { id: map.id, documentId: map.document_id, status: map.status, supersededByMapId: map.superseded_by_map_id, nodes: map.nodes_json.length, edges: map.edges_json.length },
    claimRefs: { evidenceRows: claimResult.rowCount, distinctCoveredRefs: new Set(claimResult.rows.map((r) => r.map_element_ref)).size },
    total: rows.length,
    covered: rows.filter((r) => r.covered).length,
    uncovered: uncovered.length,
    uncoveredNodes: uncovered.filter((r) => r.kind === 'node').length,
    uncoveredEdges: uncovered.filter((r) => r.kind === 'edge').length,
    uncoveredSharedEvidence: uncovered.filter((r) => r.sharedEvidence).length,
    uncoveredUniqueNoClaim: uncovered.filter((r) => !r.sharedEvidence).length,
    distinctSourceLinesSharedAcrossTwoOrMoreElements: quoteFanouts.length,
    maxFanout: quoteFanouts.length ? Math.max(...quoteFanouts) : 0,
    fanoutDistribution: Object.fromEntries([...fanoutDistribution.entries()].sort((a,b) => Number(a[0])-Number(b[0]))),
    examples: uncovered.slice(0, 12).map((r) => ({ ref: r.ref, kind: r.kind, label: r.label, evidenceQuote: r.evidenceQuote, sharedEvidence: r.sharedEvidence, quoteAlsoOnOtherElements: r.quoteAlsoOnOtherElements })),
    outPath,
  };
  console.log(JSON.stringify(summary, null, 2));
  await client.end();
})().catch((e) => { console.error(e.stack || e.message); process.exit(1); });
